void MRFSegmentPartitionDlg::CreateNbOfSpinners(int iNbIndex)
{
	if (NULL != _pPartitionFrame)
	{
		int ChildCount = _pPartitionFrame->GetChildCount();
		if (ChildCount > 0)
		{
			if (_ChildCount > iNbIndex)
			{
				for (int i = (2 * iNbIndex) + 1; i <= 2 * _ChildCount; i++)
				{
					CATDialog * pChild = _pPartitionFrame->GetChildFromChildNumber(i-1);
					if (NULL != pChild)
					{
						pChild->SetVisibility(CATDlgHide);
					}
				}
			}
			else if (_ChildCount < iNbIndex)
			{
				for (int i = (2 * _ChildCount) + 1; i <= 2 * iNbIndex; i++)
				{
					CATDialog * pChild = _pPartitionFrame->GetChildFromChildNumber(i-1);
					if (NULL != pChild)
					{
						pChild->SetVisibility(CATDlgShow);
					}
				}
			}			
		}
		else
		{
			short int Lcolumn = 0;
			short int Scolumn = 0;
			for (int i = 1; i <= iNbIndex; i++)
			{
				short int row = 0;
				if (i > 4 && i <= 8)
				{
					row = 1;
					if (5 == i)
					{
						Lcolumn = 0;
						Scolumn = 0;
					}
				}
				else if (i > 8 && i <= 12)
				{
					row = 2;
					if (9 == i)
					{
						Lcolumn = 0;
						Scolumn = 0;
					}
				}					
				else if (i > 12 && i <= 16)
				{
					row = 3;
					if (13 == i)
					{
						Lcolumn = 0;
						Scolumn = 0;
					}
				}					
				else if (i > 16 && i <= 20)
				{
					row = 4;
					if (17 == i)
					{
						Lcolumn = 0;
						Scolumn = 0;
					}
				}					
				else if (i > 20 && i <= 24)
				{
					row = 5;
					if (21 == i)
					{
						Lcolumn = 0;
						Scolumn = 0;
					}
				}
				else if (i > 24 && i <= 28)
				{
					row = 6;
					if (25 == i)
					{
						Lcolumn = 0;
						Scolumn = 0;
					}
				}
				else if (i > 28)
				{
					row = 7;
					if (29 == i)
					{
						Lcolumn = 0;
						Scolumn = 0;
					}
				}

				CATUnicodeString strIndex;
				strIndex.BuildFromNum(i);

				CATUnicodeString strLabel = " S" + strIndex + "   ";

				CATDlgLabel * pDlgLabel = new CATDlgLabel(_pPartitionFrame, (const char*)strLabel, 0 | CATDlgLabLeft);
				pDlgLabel->SetGridConstraints(row, Lcolumn, 1, 1, CATGRID_4SIDES);
				Lcolumn++;
				Scolumn++;

				CATDlgSpinner * pDlgSpinner = new CATDlgSpinner(_pPartitionFrame, (const char*)strIndex, 0 | CATDlgSpnEntry);
				pDlgSpinner->SetGridConstraints(row, Scolumn, 1, 1, CATGRID_4SIDES);
				pDlgSpinner->SetRange(0.0f, 360.0f, 3600.0f, 0);
				pDlgSpinner->SetFormat("%2gdeg");
				pDlgSpinner->SetValue(0.0f);
				Lcolumn++;
				Scolumn++;
				_pListSpinners.Append(pDlgSpinner);
			}
		}
		_ChildCount = iNbIndex;
	}
}

//-----------------------------------------------------------------------------
// MRFSegmentPartitionDlg : SetFocusOnSelectorList
// Set focus on the selected List
//-----------------------------------------------------------------------------
void MRFSegmentPartitionDlg::SetFocusOnSelectorList(CATDlgSelectorList * ipSelectorList)
{
	if (!!ipSelectorList)
	{
		static int arrRow[1] = { 0 };
		ipSelectorList->SetSelect(arrRow, 1, 0);
		SetFocusOn(ipSelectorList);

	}
}

void MRFSegmentPartitionDlg::ClearAllSelections()
{
	if (!!_pTireAssySelector)
		_pTireAssySelector->ClearSelect();

	if (!!_pPlaneSelector)
		_pPlaneSelector->ClearSelect();

	if (!!_pSegmentGeomSetSelector)
		_pSegmentGeomSetSelector->ClearSelect();	
	
	if (!!_pRefSurfaceSelector)
		_pRefSurfaceSelector->ClearSelect();	
	
	if (!!_p2DTireLayoutSelector)
		_p2DTireLayoutSelector->ClearSelect();

	if (!!_pStartPlaneSelector)
		_pStartPlaneSelector->ClearSelect();
}

void MRFSegmentPartitionDlg::SwitchRadio(int index)
{
	if (0 == index)
	{
		_pCrModeFrame->SetVisibility(CATDlgShow);
		_pEdModeFrame->SetVisibility(CATDlgHide);
	}
	else if (1 == index)
	{
		_pCrModeFrame->SetVisibility(CATDlgHide);
		_pEdModeFrame->SetVisibility(CATDlgShow);
	}
}

void MRFSegmentPartitionDlg::Update2DProgress(const CATUnicodeString istrText)
{
	if (!!_pDlgProgress)
	{
		int pos = _pDlgProgress->GetPos();

		if (0 == pos)
		{
			_pDlgProgress->SetRange(1, 50);
			_pDlgProgress->SetPos(10);
			_pDlgProgress->SetStep(1);
			_pDlgProgress->StepIt();
		}
		else
			_pDlgProgress->StepIt();

		_pLabelProgress->SetTitle(istrText);
		if (istrText.SearchSubString("Created") >= 0)
		{
			_pDlgProgress->SetPos(50);
		}

		if (CATDlgHide == _pDlgProgress->GetVisibility())
			_pDlgProgress->SetVisibility(CATDlgShow);

		if (CATDlgHide == _pLabelProgress->GetVisibility())
			_pLabelProgress->SetVisibility(CATDlgShow);
	}
}